/**
 * Calculates required modules, macros and other stuff for the external process test run
 */
/*package*/ class ProgramParametersCalculator {
  private static final Logger LOG = LogManager.getLogger(ProgramParametersCalculator.class);
  @NotNull
  private final TestsWithParametersAndConfiguration mySettings;
  @NotNull
  private final TestsWithParameters myTestsToRun;
  @NotNull
  private final SRepository myRepo;

  public ProgramParametersCalculator(@NotNull final TestsWithParametersAndConfiguration settings) {
    mySettings = settings;
    myTestsToRun = settings.myTests2Run;
    myRepo = settings.myRepo;
  }

  public String calculate() throws ExecutionException {
    boolean doINeedMPS = myTestsToRun.getParameters().needsMPS();
    return (doINeedMPS ? calcParamsWithMpsPlatformToStart() : calcParamsWithoutMPSPlatformToStart());
  }

  private String calcParamsWithoutMPSPlatformToStart() {
    List<String> testsCommandLine = ListSequence.fromList(new ArrayList<String>(ListSequence.fromList(myTestsToRun.getTests()).count() * 2));
    for (ITestNodeWrapper test : ListSequence.fromList(myTestsToRun.getTests())) {
      ListSequence.fromList(testsCommandLine).addElement((test.isTestCase() ? "-c" : "-m"));
      ListSequence.fromList(testsCommandLine).addElement(test.getFqName());
    }
    return IterableUtils.join(ListSequence.fromList(testsCommandLine), " ");
  }

  private String calcParamsWithMpsPlatformToStart() throws ExecutionException {
    ExecutorScript args = new ExecutorScript();
    ScriptData startupArgs = args.addStartupArguments();
    addModulesAndDepsToStartupArgs(startupArgs);
    addMacrosToStartupArgs(startupArgs);
    addPluginsToStartupArgs(startupArgs);
    startupArgs.setLoadBootstrapLibraries(true);

    // XXX May want to pass value of idea.additional.classpath system property further to new IdeaApplication instance to ensure plugins that are 
    // loaded from sources could get loaded in the new application as well. 
    for (ITestNodeWrapper test : ListSequence.fromList(myTestsToRun.getTests())) {
      args.addTest(test);
    }
    try {
      File tempFile = File.createTempFile("test-exec", ".xml");
      tempFile.deleteOnExit();
      Element root = new Element("tests-exec");
      args.write(root);
      JDOMUtil.writeDocument(new Document(root), tempFile);
      return tempFile.getAbsolutePath();
    } catch (IOException ex) {
      throw new ExecutionException("Failed to prepare arguments for test executor", ex);
    }
  }

  private void addPluginsToStartupArgs(@Mutable final ScriptData startupArgs) {
    List<PluginData> plugins = new UserProvidedPluginsCalculator(mySettings).calculate();
    ListSequence.fromList(plugins).visitAll(new IVisitor<PluginData>() {
      public void visit(PluginData it) {
        startupArgs.addPlugin(it);
      }
    });
  }

  private void addModulesAndDepsToStartupArgs(@Mutable ScriptData startupArgs) {
    final RepositoryDescriptor rd = new RepositoryDescriptor();
    // I've got set of reference to modules I need to present in a new MPS instance 
    // and now have to guess their locations to pass to the new instance. 
    // XXX here, we exploit the assumption module descriptor file resides under a module root 
    myRepo.getModelAccess().runReadAction(new Runnable() {
      public void run() {
        List<SModule> modules = ListSequence.fromList(new ArrayList<SModule>());
        for (SModuleReference testModule : myTestsToRun.getRequiredModules()) {
          SModule tm = testModule.resolve(myRepo);
          if (tm != null) {
            ListSequence.fromList(modules).addElement(tm);
          }
        }
        Collection<SModule> execClosure = collectExecuteCP(ListSequence.fromList(modules).distinct());
        // XXX don't we need to add respective generator module jars like we do inMpsTestsSuite and GenerateTask so tha 
        //     environment started from WithPlatformTestExecutor loads all modules properly? 
        //     OTOH, language and generator modules from the MPS platform are likely to get loaded regardless of the setting, 
        //           while languages and generators from the active project are non-deployed anyway 
        for (SModule m : CollectionSequence.fromCollection(execClosure)) {
          if (false == m instanceof AbstractModule) {
            continue;
          }
          IFile descriptorFile = ((AbstractModule) m).getDescriptorFile();
          if (descriptorFile == null) {
            continue;
          }
          // XXX in fact, for non-deployed module this would end up with a module source dir, which is not 'file' per se, but as long as there's 
          // no distinction in processing rd.files and rd.folders (ModulesMiner doesn't care), I don't bother here either. 
          rd.files.add(descriptorFile.getBundleHome().getPath());
        }
      }
    });
    startupArgs.setRepo(rd);
  }

  private Set<SModule> collectExecuteCP(Iterable<SModule> modules) {
    // yes, assuming that... 
    final Map<Solution, List<Language>> allRTs2Lang = this.getRTs2LangInRepo();
    Collection<SModule> modulesWithDeps = getExecuteDeps(Sequence.fromIterable(modules).toListSequence());
    Iterable<SModule> javaModules = CollectionSequence.fromCollection(modulesWithDeps).where(new IWhereFilter<SModule>() {
      public boolean accept(SModule it) {
        return it.getFacet(JavaModuleFacet.class) != null;
      }
    });
    // rt modules in our closure 
    Iterable<SModule> rtsModules = Sequence.fromIterable(javaModules).where(new IWhereFilter<SModule>() {
      public boolean accept(SModule it) {
        return it instanceof Solution && MapSequence.fromMap(allRTs2Lang).containsKey((Solution) it);
      }
    });
    Iterable<Language> usedLangsForRTs = Sequence.fromIterable(rtsModules).translate(new ITranslator2<SModule, Language>() {
      public Iterable<Language> translate(SModule it) {
        return MapSequence.fromMap(allRTs2Lang).get((Solution) it);
      }
    }).where(new NotNullWhereFilter<Language>()).distinct();
    // used lang for runtimes we need since we are not capable of locating the runtime classes 
    // when we are running java class for example 
    return SetSequence.fromSetWithValues(new HashSet<SModule>(), Sequence.fromIterable(javaModules).union(CollectionSequence.fromCollection(getExecuteDeps(Sequence.fromIterable(usedLangsForRTs).toListSequence()))));
  }

  private Collection<SModule> getExecuteDeps(List<? extends SModule> modules) {
    GlobalModuleDependenciesManager MANAGER = new GlobalModuleDependenciesManager(modules);
    return MANAGER.getModules(GlobalModuleDependenciesManager.Deptype.EXECUTE);
  }

  private Map<Solution, List<Language>> getRTs2LangInRepo() {
    final Map<Solution, List<Language>> res = MapSequence.fromMap(new HashMap<Solution, List<Language>>());
    Iterable<SModule> allModules = myRepo.getModules();
    Sequence.fromIterable(allModules).where(new IWhereFilter<SModule>() {
      public boolean accept(SModule it) {
        return it instanceof Language;
      }
    }).visitAll(new IVisitor<SModule>() {
      public void visit(SModule it) {
        Language language = ((Language) it);
        Collection<SModuleReference> rtRefs = language.getRuntimeModulesReferences();
        for (SModuleReference rtRef : CollectionSequence.fromCollection(rtRefs)) {
          Solution resolvedRT = (Solution) rtRef.resolve(myRepo);
          if (resolvedRT != null) {
            if (MapSequence.fromMap(res).get(resolvedRT) == null) {
              MapSequence.fromMap(res).put(resolvedRT, ListSequence.fromList(new ArrayList<Language>()));
            }
            ListSequence.fromList(MapSequence.fromMap(res).get(resolvedRT)).addElement(language);
          }
        }
      }
    });
    return res;
  }

  private void addMacrosToStartupArgs(@Mutable ScriptData startupArgs) {
    // FIXME Shall use proper ComponentHost.findComponent to access PathMacros instance 
    PathMacros pathMacros = PathMacros.getInstance();
    // XXX not sure why we iterate over user names only (not getNames()), it's the way it used to be in LanguageTestWrapper/AbstractTestWrapper for a long time 
    for (String key : pathMacros.getUserNames()) {
      String value = pathMacros.getValue(key);
      if (value != null) {
        startupArgs.addMacro(key, value);
      } else {
        // XXX EnvironmentBase is not quite friendly to null macro values. I can't decide whether it's better to relax this restriction (who cares what macro value is 
        // except its consumer?), to report a warning here or to let EnvironmentBase do that. 
        if (LOG.isEnabledFor(Level.WARN)) {
          LOG.warn(String.format("No value for macro %s, ignored", key));
        }
      }
    }
  }
}
